from collections import defaultdict, Counter
from autogen import ConversableAgent

def detect_tool_loops(agent: ConversableAgent, messages):
    tool_calls = []
    for msg in messages[-10:]:  # Last 10 messages
        if hasattr(msg, 'tool_calls') and msg.tool_calls:
            tool_calls.extend(msg.tool_calls)

    tool_counter = Counter([f'{tc['function']['name']}_{tc.get('parameters', {})}' for tc in tool_calls])

    if tool_calls and max(tool_counter.values()) >= 3:
        return {'alert': 'TOOL_LOOP_DETECTED', 'repeated_tool': tool_counter.most_common(1)[0][0]}
    return None

from collections import deque

def detect_agent_cycles(chat_history, window_size=5):
    if len(chat_history) < window_size:
        return None

    recent_speakers = deque([msg.sender for msg in chat_history[-window_size:]], maxlen=window_size)
    speaker_pattern = tuple(recent_speakers)

    # Detect A->B->A->B pattern
    if len(set(recent_speakers)) <= 2 and len(recent_speakers) == window_size:
        return {'alert': 'AGENT_CYCLE_DETECTED', 'pattern': str(speaker_pattern)}
    return None

import tiktoken
encoding = tiktoken.get_encoding('cl100k_base')

def detect_token_explosion(messages, max_tokens_per_round=2000):
    recent_round_tokens = sum(len(encoding.encode(msg.content)) for msg in messages[-5:])

    if recent_round_tokens > max_tokens_per_round:
        return {
            'alert': 'TOKEN_EXPLOSION',
            'tokens_consumed': recent_round_tokens,
            'threshold': max_tokens_per_round
        }
    return None

