from autogen import register_function
class ToolLoopGuard:
    def __init__(self):
        self.tool_history = set()
        self.max_age = 300  # 5 minutes

    def filter_reply(self, sender, recipient, reply):
        if hasattr(reply, 'tool_calls'):
            for tool_call in reply.tool_calls:
                tool_id = f"{tool_call['function']['name']}_{hash(str(tool_call.get('parameters', {})))}"
                if tool_id in self.tool_history:
                    reply.content = "[LOOP_PREVENTED] Tool call repeated. Please try different approach."
                    reply.tool_calls = []
                    break
                self.tool_history.add(tool_id)
        return reply

loop_guard = ToolLoopGuard()
config_list = [{'functions': [], 'reply_filter': loop_guard.filter_reply}]
